contents.css:
.mud-drawer.mud-drawer-fixed.mud-drawer-pos-left {
    top: 64px !important;
    bottom: 0 !important;
    height: auto !important;
}
.tca-shell-header {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: 64px;
    z-index: 1200;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 0 16px;
    background: linear-gradient(90deg, #1a1f3a, #2d1b4e);
    color: #fff;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.35);
}
.tca-shell-title {
    font-weight: 800;
    letter-spacing: 0.5px;
}
.tca-shell-spacer {
    flex: 1;
}
.tca-shell-body {
    margin-top: 64px;
    margin-bottom: 40px;
    padding: 24px;
}
.tca-shell-welcome {
    background: linear-gradient(135deg, #7c4dff, #536dfe);
    color: #fff;
    padding: 14px 18px;
    border-radius: 12px;
    margin-bottom: 16px;
}
.tca-shell-welcome-title {
    font-size: 1.15rem;
    font-weight: 700;
}
.tca-shell-welcome-sub {
    opacity: 0.85;
}

.tca-after-content {
    margin-top: 16px;
    padding: 10px 16px;
    border-radius: 10px;
    background: rgba(124, 77, 255, 0.12);
    border: 1px dashed rgba(124, 77, 255, 0.5);
    font-size: 0.82rem;
    text-align: center;
}
.tca-after-content-label {
    font-weight: 700;
}

.tca-before-content {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 16px;
    padding: 10px 16px;
    border-radius: 10px;
    background: linear-gradient(90deg, #536dfe, #7c4dff);
    color: #fff;
    font-size: 0.9rem;
    box-shadow: 0 2px 10px rgba(83, 109, 254, 0.35);
}
.tca-before-content-icon {
    font-size: 1.1rem;
    line-height: 1;
}

.tca-drawer-footer {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid rgba(124, 77, 255, 0.35);
    font-size: 0.8rem;
}
.tca-drawer-footer-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #4caf50;
    box-shadow: 0 0 6px #4caf50;
    flex: none;
}
.tca-drawer-footer-text {
    opacity: 0.85;
}

.tca-drawer-header {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 16px;
    background: linear-gradient(135deg, #1a1f3a, #2d1b4e);
    color: #fff;
}
.tca-drawer-header-logo {
    font-size: 1.6rem;
    line-height: 1;
}
.tca-drawer-header-name {
    font-weight: 800;
    letter-spacing: 0.5px;
}
.tca-drawer-header-sub {
    font-size: 0.72rem;
    opacity: 0.7;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.tcf {
    display: flex;
    align-items: center;
    gap: 12px;
    width: 100%;
    padding-inline: 12px;
    font-size: 0.78rem;
}
.tcf-grow  { flex: 1; }
.tcf-brand { font-weight: 600; }
.tcf-ver   { opacity: .6; }
.tcf-link  { color: inherit; text-decoration: none; opacity: .85; }
.tcf-link:hover { opacity: 1; text-decoration: underline; }

.tca-topbar-end {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin-right: 8px;
    padding: 3px 12px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.55);
    color: #fff;
    font-weight: 600;
    font-size: 0.78rem;
}
.tca-topbar-end-icon {
    font-size: 0.9rem;
    line-height: 1;
}

.tca-topbar-start {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin-left: 10px;
    padding: 3px 12px;
    border-radius: 999px;
    background: linear-gradient(135deg, #7c4dff 0%, #00b0ff 100%);
    color: #fff;
    font-weight: 700;
    font-size: 0.78rem;
    letter-spacing: 0.04em;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.3);
}
.tca-topbar-start-icon {
    font-size: 0.95rem;
    line-height: 1;
    margin-right: 2px;
}
